import sys
from html.parser import HTMLParser

class TableParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.in_table = False
        self.in_row = False
        self.in_cell = False
        self.current_row = []
        self.rows = []
        self.tables = []

    def handle_starttag(self, tag, attrs):
        if tag == 'table':
            self.in_table = True
        if self.in_table and tag == 'tr':
            self.in_row = True
            self.current_row = []
        if self.in_row and tag in ['td', 'th']:
            self.in_cell = True

    def handle_endtag(self, tag):
        if tag == 'table':
            self.in_table = False
            if self.rows:
                self.tables.append(self.rows)
            self.rows = []
        if tag == 'tr' and self.in_row:
            self.in_row = False
            if self.current_row:
                self.rows.append(self.current_row)
        if tag in ['td', 'th']:
            self.in_cell = False

    def handle_data(self, data):
        if self.in_cell:
            stripped = data.strip()
            if stripped:
                self.current_row.append(stripped)

p = TableParser()
for line in sys.stdin:
    p.feed(line)

for i, table in enumerate(p.tables):
    print(f"Table {i}:")
    for row in table[:15]:
        print(row)
    print("---")
